import{_ as t,a}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as n,o as s,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Add a Hugging Face Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/huggingface.md","filePath":"en/upload/huggingface.md","lastUpdated":1781962217000}'),r={name:"en/upload/huggingface.md"};function d(c,e,l,h,p,g){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="add-a-hugging-face-channel" tabindex="-1">Add a Hugging Face Channel <a class="header-anchor" href="#add-a-hugging-face-channel" aria-label="Permalink to &quot;Add a Hugging Face Channel&quot;">​</a></h1><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><p>You only need three things:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Hugging Face account</td><td>Used to generate an access token and own the repository.</td></tr><tr><td>Hugging Face User Access Token</td><td>Used by ImgBed to access the Hugging Face API, create repositories, and upload files.</td></tr><tr><td>Repository name</td><td>You can enter only the repository name, for example <code>image</code>.</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-sign-in-to-hugging-face-and-create-an-access-token" tabindex="-1">Step 1: Sign in to Hugging Face and Create an Access Token <a class="header-anchor" href="#step-1-sign-in-to-hugging-face-and-create-an-access-token" aria-label="Permalink to &quot;Step 1: Sign in to Hugging Face and Create an Access Token&quot;">​</a></h3><ol><li>Sign in to Hugging Face.</li><li>Click your avatar in the upper-right corner and open <code>Settings</code>.</li><li>Open <code>Access Tokens</code> from the left sidebar.</li><li>Create a new token.</li><li>Give the token a recognizable name.</li><li>Select <code>write</code> permission.</li><li>Copy and save the token immediately after it is created.</li></ol><p><img src="'+t+'" alt="Create a token" loading="lazy"></p><h2 id="step-2-fill-in-the-hugging-face-channel-in-imgbed" tabindex="-1">Step 2: Fill in the Hugging Face Channel in ImgBed <a class="header-anchor" href="#step-2-fill-in-the-hugging-face-channel-in-imgbed" aria-label="Permalink to &quot;Step 2: Fill in the Hugging Face Channel in ImgBed&quot;">​</a></h2><p>After selecting <code>Hugging Face</code> in Upload Settings, fill in the fields as follows:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A name you choose, such as <code>hf-primary</code>.</td></tr><tr><td>Repository name</td><td>Either a short repo name such as <code>image</code>, or a full path such as <code>username/image</code>.</td></tr><tr><td>Access Token</td><td>The Hugging Face User Access Token you just created.</td></tr><tr><td>Private repository</td><td>Turn on or off based on your needs.</td></tr><tr><td>Remark</td><td>Optional, for example <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Add the channel" loading="lazy"></p><h2 id="step-3-save-the-channel" tabindex="-1">Step 3: Save the Channel <a class="header-anchor" href="#step-3-save-the-channel" aria-label="Permalink to &quot;Step 3: Save the Channel&quot;">​</a></h2><p>After filling in the fields, click Save.</p><p>The system will then handle these details:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short repository name</td><td>ImgBed identifies the current Hugging Face account and expands the value into a full repository path.</td></tr><tr><td>Full repository path</td><td>ImgBed uses the <code>username/repository</code> path exactly as entered.</td></tr><tr><td>Repository check</td><td>If you use the current personal account path, ImgBed tries to create the repository when it does not exist. If you enter a full path manually, ImgBed uses that path directly.</td></tr><tr><td>Repository type</td><td>This channel uses a <code>dataset</code> repository.</td></tr><tr><td>Public/private state</td><td>The repository visibility is synchronized according to the current switch.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in to Hugging Face</span></span>
<span class="line"><span>-&gt; Create an Access Token</span></span>
<span class="line"><span>-&gt; Select write permission</span></span>
<span class="line"><span>-&gt; Return to ImgBed and enter the token and repository name</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; If only a repo name is entered, ImgBed adds the current username automatically</span></span>
<span class="line"><span>-&gt; If username/repo is entered, ImgBed uses it as-is</span></span>
<span class="line"><span>-&gt; ImgBed checks or creates the dataset repository</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div>`,18)])])}const y=n(r,[["render",d]]);export{f as __pageData,y as default};
